beforeSaveCustomScript:
// =====================================================
// VERSIONE: 1.5.0
// DATA: 25-05-2026
// Contratto (Quote) — beforeSave
// Nome (modifica manuale): data - cliente - descrizione - importo
// Nome: formula solo se NON creato da CreateContratto (PHP imposta il nome)
// =====================================================

if (hookVersion == null || !string\contains(hookVersion, 'CreateContratto')) {

importoFinale = importoContratto;
if (importoFinale == null || importoFinale == 0) {
    importoFinale = amount;
}
if (importoFinale == null || importoFinale == 0) {
    importoFinale = grandTotalAmount;
}
if ((importoFinale == null || importoFinale == 0) && opportunityId != null) {
    importoFinale = record\attribute('Opportunity', opportunityId, 'importoOpportunit');
}
if ((importoFinale == null || importoFinale == 0) && opportunityId != null) {
    importoFinale = record\attribute('Opportunity', opportunityId, 'amount');
}

clienteLabel = accountName;
if (clienteLabel == null || clienteLabel == '') {
    clienteLabel = billingContactName;
}
if (clienteLabel == null || clienteLabel == '') {
    clienteLabel = shippingContactName;
}
if ((clienteLabel == null || clienteLabel == '') && accountId != null) {
    clienteLabel = record\attribute('Account', accountId, 'name');
}
if ((clienteLabel == null || clienteLabel == '') && billingContactId != null) {
    clienteLabel = record\attribute('Contact', billingContactId, 'name');
}
if (clienteLabel == null || clienteLabel == '') {
    clienteLabel = billingContact.name;
}
if (clienteLabel == null || clienteLabel == '') {
    clienteLabel = account.name;
}
if ((clienteLabel == null || clienteLabel == '') && opportunityId != null) {
    clienteLabel = record\attribute('Opportunity', opportunityId, 'leadName');
}
if (clienteLabel == null || clienteLabel == '') {
    clienteLabel = opportunity.lead.name;
}
if (clienteLabel == null || clienteLabel == '') {
    clienteLabel = shippingContact.name;
}

descrizioneLabel = description;
if (descrizioneLabel == null || descrizioneLabel == '') {
    descrizioneLabel = opportunity.description;
}
if ((descrizioneLabel == null || descrizioneLabel == '') && opportunityId != null) {
    descrizioneLabel = record\attribute('Opportunity', opportunityId, 'description');
}

name = string\concatenate(
    dateQuoted,
    ' - ',
    clienteLabel,
    ' - ',
    descrizioneLabel,
    ' - €. ',
    importoFinale
);

}

// =====================================================
// CALCOLO TAX RATE
// =====================================================

if (amount != null && amount != 0 && taxAmount != null) {
    taxRate = math\round(
        (
            taxAmount * 100
        ) / amount,
        0
    ) / 100;
}

// =====================================================
// CALCOLO ALIQUOTA IVA
// =====================================================

if (taxRate != null) {
    aliquotaIVA = math\round(
        taxRate * 100,
        2
    );
}

// =====================================================
// CALCOLO MARGINE
// =====================================================

if (amount != null && prezzoCodice != null && taxRate != null) {
    minusPlus = amount - (
        prezzoCodice / (
            1 + taxRate
        )
    );
}

// =====================================================
// COPIA INDIRIZZI DA ACCOUNT (solo se vuoti sul contratto)
// =====================================================

if (billingAddressStreet == null || billingAddressStreet == '') {
    billingAddressStreet = account.billingAddressStreet;
    if ((billingAddressStreet == null || billingAddressStreet == '') && accountId != null) {
        billingAddressStreet = record\attribute('Account', accountId, 'billingAddressStreet');
    }
}

if (billingAddressCity == null || billingAddressCity == '') {
    billingAddressCity = account.billingAddressCity;
    if ((billingAddressCity == null || billingAddressCity == '') && accountId != null) {
        billingAddressCity = record\attribute('Account', accountId, 'billingAddressCity');
    }
}

if (billingAddressPostalCode == null || billingAddressPostalCode == '') {
    billingAddressPostalCode = account.billingAddressPostalCode;
    if ((billingAddressPostalCode == null || billingAddressPostalCode == '') && accountId != null) {
        billingAddressPostalCode = record\attribute('Account', accountId, 'billingAddressPostalCode');
    }
}

if (billingAddressState == null || billingAddressState == '') {
    billingAddressState = account.billingAddressState;
    if ((billingAddressState == null || billingAddressState == '') && accountId != null) {
        billingAddressState = record\attribute('Account', accountId, 'billingAddressState');
    }
}

if (billingAddressCountry == null || billingAddressCountry == '') {
    billingAddressCountry = account.billingAddressCountry;
    if ((billingAddressCountry == null || billingAddressCountry == '') && accountId != null) {
        billingAddressCountry = record\attribute('Account', accountId, 'billingAddressCountry');
    }
}

if (shippingAddressStreet == null || shippingAddressStreet == '') {
    shippingAddressStreet = account.shippingAddressStreet;
    if ((shippingAddressStreet == null || shippingAddressStreet == '') && accountId != null) {
        shippingAddressStreet = record\attribute('Account', accountId, 'shippingAddressStreet');
    }
}

if (shippingAddressCity == null || shippingAddressCity == '') {
    shippingAddressCity = account.shippingAddressCity;
    if ((shippingAddressCity == null || shippingAddressCity == '') && accountId != null) {
        shippingAddressCity = record\attribute('Account', accountId, 'shippingAddressCity');
    }
}

if (shippingAddressPostalCode == null || shippingAddressPostalCode == '') {
    shippingAddressPostalCode = account.shippingAddressPostalCode;
    if ((shippingAddressPostalCode == null || shippingAddressPostalCode == '') && accountId != null) {
        shippingAddressPostalCode = record\attribute('Account', accountId, 'shippingAddressPostalCode');
    }
}

if (shippingAddressState == null || shippingAddressState == '') {
    shippingAddressState = account.shippingAddressState;
    if ((shippingAddressState == null || shippingAddressState == '') && accountId != null) {
        shippingAddressState = record\attribute('Account', accountId, 'shippingAddressState');
    }
}

if (shippingAddressCountry == null || shippingAddressCountry == '') {
    shippingAddressCountry = account.shippingAddressCountry;
    if ((shippingAddressCountry == null || shippingAddressCountry == '') && accountId != null) {
        shippingAddressCountry = record\attribute('Account', accountId, 'shippingAddressCountry');
    }
}
